const items = $input.all();
const rows = items[0].json;

// Veri gelmediyse veya boşsa dur
if (!rows || !Array.isArray(rows) || rows.length < 20) {
    throw new Error("Binance'den veri alınamadı!");
}

const period = 14;
// Kapanış fiyatlarını güvenli bir şekilde al
const closes = rows.map(r => parseFloat(r[4])).filter(v => !isNaN(v));

let gains = 0, losses = 0;
for (let i = closes.length - period; i < closes.length; i++) {
    let diff = closes[i] - closes[i - 1];
    if (diff >= 0) gains += diff;
    else losses += Math.abs(diff);
}

let rsi = losses === 0 ? 100 : 100 - (100 / (1 + (gains / losses)));
let price = closes[closes.length - 1];
let prev = closes[closes.length - 2];
let move = ((price - prev) / prev) * 100;

// Veriler sayı değilse hata fırlat (Backend'e boş gitmesin)
if (isNaN(price) || isNaN(rsi)) {
    throw new Error("Hesaplama hatası: Fiyat veya RSI bulunamadı.");
}

return [{
    json: {
        symbol: "BTCUSDT",
        price: Number(price.toFixed(2)),
        rsi: Number(rsi.toFixed(2)),
        is_bearish: rsi < 35 || move < -0.2,
        is_bullish: rsi > 65 || move > 0.2,
        panic_score: move < -1.5 ? Number((Math.abs(move) * 10).toFixed(2)) : 0
    }
}];
